from collections import deque
def swim_in_water(grid):
    n = len(grid)
    lo = max(grid[0][0], grid[n-1][n-1])
    hi = max(max(row) for row in grid)
    def ok(T):
        if grid[0][0] > T:
            return False
        vis = [[False]*n for _ in range(n)]
        q = deque([(0,0)])
        vis[0][0] = True
        while q:
            x, y = q.popleft()
            if (x, y) == (n-1, n-1):
                return True
            for dx, dy in [(1,0),(-1,0),(0,1),(0,-1)]:
                i, j = x + dx, y + dy
                if 0 <= i < n and 0 <= j < n and not vis[i][j] and grid[i][j] <= T:
                    vis[i][j] = True
                    q.append((i, j))
        return False
    while lo < hi:
        mid = (lo + hi) // 2
        if ok(mid):
            hi = mid
        else:
            lo = mid + 1
    return lo

